#include<bits/stdc++.h>
using namespace std;

int dp[105][105][105], n;
string dp2[105][105][105];
string a,b,c;

int main() {
	cin>>a>>b>>c;
    a=' '+a;
    b=' '+b;
    c=' '+c;
	for (int i = 1; i < a.size(); i++) {
		for (int j = 1; j < b.size(); j++) {
            for(int k = 1; k < c.size(); k++){
    			if (a[i] == b[j] && b[j]==c[k]) {
    				dp[i][j][k] = dp[i - 1][j - 1][k - 1] + 1;
                    dp2[i][j][k] = dp2[i - 1][j - 1][k - 1] + a[i];
    			} else {
    				if(max({dp[i][j][k - 1],dp[i][j - 1][k], dp[i-1][j][k]}) == dp[i][j - 1][k]){
                        dp[i][j][k] = dp[i][j - 1][k];
                        dp2[i][j][k] = dp2[i][j - 1][k]; 
                    }else if(max({dp[i][j][k - 1],dp[i][j - 1][k], dp[i-1][j][k]}) == dp[i][j][k - 1]){
                        dp[i][j][k] = dp[i][j][k - 1];
                        dp2[i][j][k] = dp2[i][j][k - 1];
                    }else{
                         dp[i][j][k] = dp[i - 1][j][k];
                        dp2[i][j][k] = dp2[i - 1][j][k]; 
                    }
    			}
            }
		}

	}
	cout << dp2[a.size() - 1][b.size() - 1][c.size() -1];
	return 0;
}
